-- 6. Ramsgate × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'ramsgate',
  'Social media is where Ramsgate''s independent community discovers and champions local businesses. The town has active Facebook groups where residents share recommendations with passionate loyalty, Instagram accounts dedicated to the Royal Harbour and Thanet coast that amplify local businesses organically, and a growing foodie community on social media that is putting Addington Street on the map. Yet many Ramsgate businesses have social profiles that were thrown together hastily and fail to capitalise on this engaged local audience. A brilliant harbour-front restaurant with a Facebook page that has not been updated since last summer. A York Street shop with an Instagram bio that says nothing about what they sell or where they are. A service provider with no Google Business Profile at all. In Ramsgate''s tight-knit community, where a single recommendation in the right Facebook group can fill your diary for a month, your social media setup is the difference between catching that wave and being invisible when it arrives.',
  'Ramsgate''s social media landscape has distinct characteristics. Facebook groups are the primary recommendation engine for local services, with active communities covering Ramsgate specifically and the wider Thanet coast. Instagram is growing around food photography on Addington Street, harbour sunset shots from the Royal Harbour, and heritage content featuring the Ramsgate Tunnels and Pugin''s architecture. Google Business Profile is crucial for capturing the walk-in discovery traffic around the harbour. The local audience is engaged but discerning: overly promotional content is called out quickly in community groups.',
  'Social media quality among Ramsgate businesses is generally low. Profile images are often blurry logos, business information is frequently outdated, and there is little strategic thinking about content or engagement. The Addington Street dining scene has a few well-managed Instagram accounts that demonstrate what is possible, but these are exceptions. Most Ramsgate businesses are missing the organic discovery and recommendation traffic that their social presence should be capturing.',
  'We set up Ramsgate social media profiles as proper business tools designed to capture the town''s engaged local audience. Every profile gets professional branded imagery, complete and accurate information, optimised descriptions targeting Ramsgate and Thanet, and a content framework aligned with the community''s preferences. We position your profiles to benefit from Ramsgate''s active recommendation culture.',
  '{"population": 40000, "district": "Thanet", "thanet_population": 141000, "key_areas": ["Royal Harbour", "Addington Street", "York Street", "Harbour front"], "social_landscape": "active Facebook recommendation groups, growing Instagram food and harbour content"}',
  '[{"title": "Ramsgate businesses losing recommendation traffic to poor social profiles", "description": "A local recommends your business in a Ramsgate Facebook group. The potential customer clicks through to your page and finds an outdated cover image, incorrect opening hours, and no recent posts. They close the page and move on. In a town where community recommendations drive significant business, a poor social profile wastes every referral."}, {"title": "No Instagram presence for Ramsgate businesses in a visually driven harbour town", "description": "The Royal Harbour, Addington Street dining, and Ramsgate Main Sands generate enormous visual content that circulates on Instagram. Businesses without an Instagram presence are invisible to the audience discovering Ramsgate through these images. Harbour-front venues without Instagram are missing their most powerful free marketing channel."}, {"title": "Missing Google Business Profile costing Ramsgate businesses walk-in trade", "description": "Visitors at the Royal Harbour search Google for nearby restaurants, shops, or services. Businesses without a claimed, optimised Google Business Profile do not appear in the map results. The visitor walks past your door and into a competitor whose listing shows up with photos, reviews, and opening hours."}]',
  '[{"title": "Professional Ramsgate social media profile setup across all relevant platforms", "description": "We set up or overhaul your Facebook, Instagram, and Google Business profiles with professional branded imagery, complete business information, and optimised descriptions referencing the Royal Harbour, Addington Street, York Street, and wider Ramsgate area. Every profile is consistent, accurate, and ready to convert social discovery into business."}, {"title": "Community-first content framework for Ramsgate''s social culture", "description": "We create a content plan aligned with how Ramsgate''s community actually engages: authentic harbour content, behind-the-scenes glimpses that resonate in a town that values realness, and seasonal content tied to Ramsgate events and the coastal calendar. The framework makes consistent posting achievable without requiring hours of planning."}, {"title": "Recommendation-ready profiles for Ramsgate''s Facebook group economy", "description": "We optimise your profiles specifically for the moment someone recommends your business in a Ramsgate Facebook group. Clear professional imagery, compelling descriptions, and prominent contact information ensure that every recommendation converts into a customer rather than being lost to a poorly presented profile."}]',
  '[{"question": "Which social media platforms matter most for Ramsgate businesses?", "answer": "Facebook is essential for Ramsgate''s local recommendation economy. Instagram is critical for harbour-front hospitality and any visually-driven business. Google Business Profile is vital for walk-in discovery around the Royal Harbour. We assess your business type and prioritise the platforms where your Ramsgate customers actually spend their time."}, {"question": "How do I engage with Ramsgate Facebook groups without being spammy?", "answer": "We set up your profile to look professional when group members check you out after a recommendation, and provide guidelines for authentic community engagement. Ramsgate groups respond positively to genuine participation and react negatively to overt promotion. We help you find the balance that builds reputation."}, {"question": "How long does social media setup take for a Ramsgate business?", "answer": "Complete setup covering Facebook, Instagram, and Google Business Profile takes five to seven working days. This includes professional imagery, optimised profiles, branded content templates, and a content framework. Businesses on Addington Street or the harbour front may benefit from a photography session to capture the setting."}, {"question": "Can you manage my Ramsgate social media ongoing?", "answer": "We offer ongoing management for businesses that prefer to hand off posting entirely. However, many Ramsgate clients find that the content framework and templates we provide make self-management straightforward. Ramsgate''s community values authenticity, and owner-generated content often performs best when paired with our professional setup."}]',
  'trust'
)
