-- 9. Ramsgate × AI Chatbots
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'ai-chatbots',
  'ramsgate',
  'Ramsgate''s independent business community faces a customer communication challenge that is becoming unsustainable. As the town''s reputation grows, particularly around the Royal Harbour dining scene and Addington Street, enquiry volumes are increasing while team sizes remain small. An Addington Street restaurant owner who personally responds to every Instagram DM and email. A York Street retailer who misses messages during busy trading hours. A service provider who cannot respond to evening enquiries because they are at home with their family. AI chatbots resolve this tension by providing instant, knowledgeable responses to the questions that consume the most time, while seamlessly handing over to a human when genuine personal attention is needed. We build chatbots trained on your specific Ramsgate business that understand your services, your harbour-front location, your availability, and the answers to every common question you receive.',
  'Ramsgate''s customer communication patterns revolve around the harbour economy. Harbour-front restaurants receive heavy booking enquiries, especially during summer and weekends. York Street shops field product availability and opening hours questions. Service businesses covering the Thanet coast handle repeated questions about coverage areas and pricing. Heritage visitors ask about Ramsgate Tunnels, Pugin''s architecture, and walking routes. The compact harbour area means many enquiries arrive when businesses are at peak operational capacity and physically cannot respond.',
  'AI chatbot adoption in Ramsgate is non-existent. No local businesses are using trained chatbots. A handful use basic auto-reply messages on Facebook and Instagram, but these are generic holding responses rather than intelligent conversation. The absence of any chatbot competition means the first Ramsgate businesses to implement trained AI will dramatically improve their customer service compared to every local competitor.',
  'We build AI chatbots for Ramsgate businesses that understand the harbour-front context, local geography, and your specific offerings. The chatbot handles booking enquiries for Addington Street restaurants, product questions for York Street shops, and service queries for wider Ramsgate businesses. It responds instantly at any hour and captures detailed information for enquiries that require human follow-up.',
  '{"population": 40000, "district": "Thanet", "thanet_population": 141000, "key_areas": ["Royal Harbour", "Addington Street", "York Street", "Harbour front"], "chatbot_adoption": "zero"}',
  '[{"title": "Ramsgate restaurant owners personally answering every DM during service", "description": "An Addington Street restaurant owner checks their phone between courses to respond to Instagram booking enquiries. The quality of both the response and the service suffers. During a busy Saturday evening, twenty messages go unanswered until midnight. Several of those prospective diners have already booked elsewhere by then."}, {"title": "York Street retailers missing enquiries during trading hours", "description": "A customer messages a Ramsgate shop about a product they saw on Instagram. The retailer is serving in-store customers and does not see the message for four hours. By then, the customer has found the item elsewhere. The retailer had the stock and would have made the sale if they could have responded instantly."}, {"title": "Ramsgate service businesses losing evening leads to silence", "description": "A Thanet homeowner searches for a local service provider at 9pm, submits an enquiry through a Ramsgate business website, and hears nothing until the next morning. Meanwhile, they have contacted two other providers, and the first to respond gets the job. Ramsgate businesses without automated response lose leads during the hours when consumers actually search."}]',
  '[{"title": "AI chatbot trained on your Ramsgate business specifics", "description": "We build a chatbot that knows your menu, products, services, pricing, opening hours, harbour-front location details, and parking information. It answers the questions your Ramsgate customers ask most frequently with accurate, helpful responses that sound natural and reflect your business personality."}, {"title": "Booking-integrated chatbot for Ramsgate harbour-front hospitality", "description": "For Addington Street restaurants and harbour-front venues, we integrate the chatbot with your booking system. It checks availability, suggests alternatives when your preferred time is full, and confirms reservations instantly. The DM-to-booking process that currently takes fifteen minutes of back-and-forth happens in seconds."}, {"title": "After-hours lead capture for Ramsgate''s evening enquiry peak", "description": "When potential customers contact your Ramsgate business outside operating hours, the chatbot provides helpful immediate responses, captures their enquiry details, and queues a notification for your morning. No lead sits unanswered overnight, and you start each day with qualified, well-documented enquiries ready for follow-up."}]',
  '[{"question": "Will a chatbot feel appropriate for a personal, independent Ramsgate business?", "answer": "Yes. We design the chatbot''s personality to match your brand. For a relaxed Addington Street restaurant, it is warm and welcoming. For a professional service, it is efficient and knowledgeable. The chatbot extends your team rather than replacing its character, and customers who need personal attention are always connected to a human."}, {"question": "Can the chatbot handle Ramsgate-specific questions like directions and parking?", "answer": "Yes. We train it on local knowledge relevant to your business: directions from the Royal Harbour, parking options near Addington Street, walking routes from Ramsgate Main Sands, and any other location-specific information your customers regularly ask about. The chatbot sounds like someone who knows the town."}, {"question": "How does the chatbot handle complex enquiries it cannot resolve?", "answer": "It captures the customer''s details and question, provides an immediate acknowledgement, and sends you a notification with full conversation context. You pick up the enquiry with all the information you need. The customer feels helped rather than ignored, which is a significant improvement over the current experience at most Ramsgate businesses."}, {"question": "How quickly can a chatbot be set up for my Ramsgate business?", "answer": "Most implementations are live within two weeks. The first week covers learning your business, training the AI on your services and common questions, and the second week involves testing and refinement. After launch, the chatbot improves continuously as it handles real conversations with your Ramsgate customers."}]',
  'authority'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  local_context = EXCLUDED.local_context,
  competition_landscape = EXCLUDED.competition_landscape,
